var main = tree.get_root().get_node_or_null("Main")
if main == null: main = tree.current_scene
var unit = GameState.state["units"]["U_TA_BOYZ"]
var mid = ""
for m in unit["models"]:
	if str(m.get("model_type","")) == "boy":
		mid = str(m["id"])
		break
var txt = str(main._build_model_profile_hover_text(unit, mid))
return ("Slugga" in txt) and not ("hoota" in txt) and not ("Rokkit" in txt) and not ("Kombi" in txt)

var main = tree.get_root().get_node_or_null("Main")
if main == null: main = tree.current_scene
RulesEngine.get_unit_weapons("U_TA_BURNA", GameState.state)
var unit = GameState.state["units"]["U_TA_BURNA"]
var mid = ""
for m in unit["models"]:
	var lo = m.get("ranged_loadout", [])
	if lo is Array and lo.has("Big shoota"):
		mid = str(m["id"])
		break
var txt = str(main._build_model_profile_hover_text(unit, mid))
return (mid != "") and ("Big shoota" in txt) and not ("Burna" in txt.replace("Burna Boyz",""))

var main = tree.get_root().get_node_or_null("Main")
if main == null: main = tree.current_scene
RulesEngine.get_unit_weapons("U_TA_BURNA", GameState.state)
var unit = GameState.state["units"]["U_TA_BURNA"]
var mid = ""
for m in unit["models"]:
	var lo = m.get("ranged_loadout", [])
	if lo is Array and lo.has("Burna"):
		mid = str(m["id"])
		break
var txt = str(main._build_model_profile_hover_text(unit, mid))
return (mid != "") and ("Burna" in txt) and not ("Big shoota" in txt)

var main = tree.get_root().get_node_or_null("Main")
if main == null: main = tree.current_scene
var panel = main.get_node_or_null("UnitStatsPanel")
if panel == null: return "NO_PANEL"
var unit = GameState.state["units"]["U_TA_BOYZ"]
panel.set_collapsed(false)
panel.display_unit(unit)
var parts = []
var stack = [panel.player_composition_container]
while stack.size() > 0:
	var n = stack.pop_back()
	if n == null: continue
	if n is Label: parts.append(str(n.text))
	for c in n.get_children(): stack.append(c)
var txt = " || ".join(parts)
var ok = ("Slugga" in txt) and not ("Big shoota" in txt) and not ("Rokkit" in txt) and not ("Kombi" in txt)
return "OK" if ok else ("BAD: " + txt)

